@props([
    'defaultValue' => null,
    'type' => 'single',
    'class' => '',
    'keepOneOpen' => false,
    'multiple' => false,
])

<div x-accordion @if ($defaultValue && $defaultValue != '') data-default-value="{{ $defaultValue }}" @endif
    @if ($keepOneOpen) data-prevent-closing-all @endif data-accordion-type="{{ $multiple ? 'multiple' : $type }}"
    {{ $attributes->class([$class]) }}>
    {{ $slot }}
</div>

@props(['variant' => 'default', 'intent' => 'gray', 'id', 'class' => null])

@php
    use App\Flexiwind\UiHelper;
    $variants = UiHelper::getVariants();

    $className = '';
    $variantClass = UiHelper::getClasses($variant, $intent);
    if ($variant === 'default') {
        $className = ' border-b border-border ';
    }

    $className .= "{$class} {$variantClass}";

@endphp

<div data-accordion-item data-accordion-value="{{ $id }}" class="{{ $className }}">
    {{ $slot }}
</div>

@props(['class'=>''])
<button data-accordion-trigger aria-label="toggle button"
    class="w-full flex justify-between items-center {{ $class }}">
    {{ $slot }}
</button>

@props(['type' => 'icon', 'icon' => 'ph--caret-down'])

@if ($type === 'icon')
    <span aria-hidden
        {{ $attributes->class([
            'flex text-fg-muted size-3.5 iconify group-aria-expanded:rotate-180 in-aria-expanded:rotate-180',
            'ease-linear duration-200',
            $icon,
        ]) }}></span>
@elseif($type === 'plus-sign')
    <span aria-hidden
        {{ $attributes->class([
            'flex text-fg-muted relative size-2.5 disclosure-indicator-plus disclosure-indicator-to-minus',
        ]) }}></span>
@endif

import {Accordion as FlexillaAccordion} from "@flexilla/accordion"

export function AccordionPlugin(Alpine) {
    Alpine.directive("accordion", (el, {}, {cleanup}) => {
        const accordion = new FlexillaAccordion(el)
        cleanup(()=>{
            accordion.cleanup()
        })
    });
}
